import{_ as s,c as l,o as e,ae as i}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"CSS常见需求","description":"","frontmatter":{},"headers":[],"relativePath":"document/CssCase.md","filePath":"document/CssCase.md"}'),n={name:"document/CssCase.md"};function t(o,a,p,r,c,d){return e(),l("div",null,a[0]||(a[0]=[i(`<h1 id="css常见需求" tabindex="-1">CSS常见需求 <a class="header-anchor" href="#css常见需求" aria-label="Permalink to &quot;CSS常见需求&quot;">​</a></h1><h2 id="清除浮动" tabindex="-1">清除浮动 <a class="header-anchor" href="#清除浮动" aria-label="Permalink to &quot;清除浮动&quot;">​</a></h2><ul><li>BFC清除浮动 overflow: hidden</li><li>通过clear清除浮动 clear:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.clearfix {</span></span>
<span class="line"><span>    zoom: 1;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>.clearfix::after {</span></span>
<span class="line"><span>    content: &quot;&quot;;</span></span>
<span class="line"><span>    display: block;</span></span>
<span class="line"><span>    clear: both;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="_1px边框解决方案" tabindex="-1">1px边框解决方案 <a class="header-anchor" href="#_1px边框解决方案" aria-label="Permalink to &quot;1px边框解决方案&quot;">​</a></h2><p>高分屏比普通屏幕分辨率更高，所以移动端的1px边框就会看起来较粗 解决方案：</p><ul><li>使用0.5px边框 先查询浏览器是否支持设置0.5px边框 无法兼容安卓及IOS 8以下</li><li>border-image</li><li>background-image</li><li>多背景渐变实现</li><li>使用box-shadow模拟边框</li><li>viewport + rem 实现 全局修改，适合新项目</li><li>伪类 + transform 实现 （先去掉边框 再添加一个伪类 在伪类中实现边框 并通过transform scale(0.5)来解决1px边框问题） 适合老项目，局部修改</li></ul><h2 id="清除浏览器默认样式" tabindex="-1">清除浏览器默认样式 <a class="header-anchor" href="#清除浏览器默认样式" aria-label="Permalink to &quot;清除浏览器默认样式&quot;">​</a></h2><p>reset.css 及 后来的 Normalize.css</p><h2 id="长文本处理" tabindex="-1">长文本处理 <a class="header-anchor" href="#长文本处理" aria-label="Permalink to &quot;长文本处理&quot;">​</a></h2><p>超出部分换行 overflow-wrap:break-word</p><p>字符超出位置使用连字符 hyphens: auto</p><p>单行文本超出显示省略号</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.ellipsis {</span></span>
<span class="line"><span>  white-space: nowrap;</span></span>
<span class="line"><span>  overflow: hidden;</span></span>
<span class="line"><span>  text-overflow: ellipsis;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>多行文本超出显示省略号</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.ellipsis {</span></span>
<span class="line"><span>  overflow: hidden;</span></span>
<span class="line"><span>  text-overflow: ellipsis;</span></span>
<span class="line"><span>  display: -webkit-box;</span></span>
<span class="line"><span>  -webkit-line-clamp: 2;</span></span>
<span class="line"><span>  -webkit-box-orient: vertical;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="水平垂直居中" tabindex="-1">水平垂直居中 <a class="header-anchor" href="#水平垂直居中" aria-label="Permalink to &quot;水平垂直居中&quot;">​</a></h2><p>场景：</p><ul><li>单行文本、inline或inline-block元素</li><li>固定宽高的块级盒子</li><li>不固定宽高的块级盒子</li></ul><h3 id="单行文本、inline或inline-block元素" tabindex="-1">单行文本、inline或inline-block元素 <a class="header-anchor" href="#单行文本、inline或inline-block元素" aria-label="Permalink to &quot;单行文本、inline或inline-block元素&quot;">​</a></h3><ul><li>水平居中 text-align: center</li><li>垂直居中 <ul><li>通过设置上下内边距一致，达到垂直居中的效果</li><li>通过设置height和line-height来达到垂直居中</li></ul></li></ul><h3 id="固定宽高的块级盒子" tabindex="-1">固定宽高的块级盒子 <a class="header-anchor" href="#固定宽高的块级盒子" aria-label="Permalink to &quot;固定宽高的块级盒子&quot;">​</a></h3><ul><li>absolute + 负margin left、top 50%，margin负的盒子的一半</li><li>absolute + margin auto left、top、right、bottom全为0，margin：auto</li><li>absolute + calc left: calc(50% - 50px)</li></ul><h3 id="不固定宽高的块级盒子" tabindex="-1">不固定宽高的块级盒子 <a class="header-anchor" href="#不固定宽高的块级盒子" aria-label="Permalink to &quot;不固定宽高的块级盒子&quot;">​</a></h3><ul><li>absolute + transform</li><li>inline-block + text-align + vertical-align</li><li>writing-mode</li><li>table-cell</li><li>flex</li><li>grid</li></ul><h2 id="常用布局" tabindex="-1">常用布局 <a class="header-anchor" href="#常用布局" aria-label="Permalink to &quot;常用布局&quot;">​</a></h2><p>两栏布局 左侧固定，右侧自适应</p><ul><li>float + overflow(BFC原理)</li><li>float + margin</li><li>flex</li><li>grid</li></ul><p>三栏布局 两侧栏宽度固定 中间自适应</p><ul><li>圣杯布局 浮动 + 相对定位 + 负margin</li><li>双飞翼布局 浮动 + margin</li><li>float + overflow(BFC原理)</li><li>flex</li><li>grid</li></ul><p>多列等高布局</p><ul><li>浮动 + padding + 负margin</li><li>设置父级背景图片 + 百分比</li></ul><p>三行布局(头尾定高主栏自适应)</p><ul><li>calc</li><li>absolute</li><li>flex</li><li>grid</li></ul><h2 id="postcss、sass、less异同-以及配置使用" tabindex="-1">PostCSS、Sass、Less异同，以及配置使用 <a class="header-anchor" href="#postcss、sass、less异同-以及配置使用" aria-label="Permalink to &quot;PostCSS、Sass、Less异同，以及配置使用&quot;">​</a></h2><ul><li>编译环境不同：Sass安装需要Ruby环境，在服务端处理，Less需要引入less.js来处理代码</li><li>变量符号不一样，less是@，Scss是$</li><li>输出设置不一样，Less没有输出设置，Sass提供4种输出选项：nested、compact、compressed、expanded</li><li>处理条件语句不一样：Sass支持条件语句，可以使用if else for等，Less的条件语句是when等关键词</li><li>引用外部文件，文件名如果以下划线_开头，Sass回认为该文件是一个引用文件，不会编译成css文件，less引用外部文件和css中@import没什么差异</li><li>工具库不一样，Sass工具库Compass，less有UI组件库Bootstrap</li><li>PostCSS的主要功能只有两个 第一个就是把CSS解析成JS可以操作的AST,第二个就是调用插件来处理AST并得到结果。PostCSS一般不单独使用，而是与已有的构建工具进行集成</li></ul><h2 id="如何防止css阻塞渲染" tabindex="-1">如何防止CSS阻塞渲染 <a class="header-anchor" href="#如何防止css阻塞渲染" aria-label="Permalink to &quot;如何防止CSS阻塞渲染&quot;">​</a></h2><p>使用媒体类型和媒体查询</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;link href=&quot;style.css&quot; rel=&quot;stylesheet&quot;&gt;  //阻塞</span></span>
<span class="line"><span>&lt;link href=&quot;print.css&quot; rel=&quot;stylesheet&quot; media=&quot;print&quot;&gt;  // 不阻塞</span></span>
<span class="line"><span>&lt;link href=&quot;other.css&quot; rel=&quot;stylesheet&quot; media=&quot;(min-width: 40em)&quot;&gt; // 符合媒体查询条件时阻塞</span></span></code></pre></div><h2 id="移动端样式问题汇总" tabindex="-1">移动端样式问题汇总 <a class="header-anchor" href="#移动端样式问题汇总" aria-label="Permalink to &quot;移动端样式问题汇总&quot;">​</a></h2><h3 id="input-框disable时的样式问题" tabindex="-1">input 框disable时的样式问题 <a class="header-anchor" href="#input-框disable时的样式问题" aria-label="Permalink to &quot;input 框disable时的样式问题&quot;">​</a></h3><ul><li>在ios下，disable状态的输入框 会默认加上一个透明度，导致字体颜色变化</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  &lt;!-- 解决方案 --&gt;</span></span>
<span class="line"><span>  input:disabled, input[disabled], textarea:disabled, textarea[disabled]{</span></span>
<span class="line"><span>    color: #af8867!important;</span></span>
<span class="line"><span>    -webkit-text-fill-color:#af8867!important; // ios 和 安卓9.0 必须添加此属性，才会生效</span></span>
<span class="line"><span>    background-color: transparent!important;</span></span>
<span class="line"><span>    opacity: 1!important;</span></span>
<span class="line"><span>  }</span></span></code></pre></div><h3 id="移动端手机点击输入框的时候输入框-页面-会变大" tabindex="-1">移动端手机点击输入框的时候输入框(页面)会变大 <a class="header-anchor" href="#移动端手机点击输入框的时候输入框-页面-会变大" aria-label="Permalink to &quot;移动端手机点击输入框的时候输入框(页面)会变大&quot;">​</a></h3><ul><li>由于弹出了输入框，导致输入框及页面变大 在head的meta标签中添加 user-scalable=no 可以解决</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!-- 解决方案   在head下添加以下代码 --&gt;</span></span>
<span class="line"><span>&lt;meta content=&quot;initial-scale=1.0, minimum-scale=1.0, maximum-scale=2.0, user-scalable=no, width=device-width&quot; name=&quot;viewport&quot;&gt;</span></span></code></pre></div><h3 id="手机端点击时的背景色设置" tabindex="-1">手机端点击时的背景色设置 <a class="header-anchor" href="#手机端点击时的背景色设置" aria-label="Permalink to &quot;手机端点击时的背景色设置&quot;">​</a></h3><p>用vue3开发移动端项目时，当点击一个元素时，元素会有一个默认的背景颜色，半透明的灰色 可以禁用默认背景颜色 -webkit-tag-highlight-color: transparent; 这个属性是设定元素在移动设备上触发点击事件时 相应的背景框的颜色</p><h2 id="浏览器兼容性问题汇总" tabindex="-1">浏览器兼容性问题汇总 <a class="header-anchor" href="#浏览器兼容性问题汇总" aria-label="Permalink to &quot;浏览器兼容性问题汇总&quot;">​</a></h2><h3 id="ie兼容性问题" tabindex="-1">IE兼容性问题 <a class="header-anchor" href="#ie兼容性问题" aria-label="Permalink to &quot;IE兼容性问题&quot;">​</a></h3><ul><li>ie下input事件会在(jq中)初始化时触发一次，解决方案是先初始化focus事件，在focus事件中绑定input事件</li></ul><h3 id="firefox兼容性问题" tabindex="-1">firefox兼容性问题 <a class="header-anchor" href="#firefox兼容性问题" aria-label="Permalink to &quot;firefox兼容性问题&quot;">​</a></h3><ul><li>不支持 overflow: overlay; 属性 需要用 overflow:auto; 做兼容处理</li></ul>`,53)]))}const b=s(n,[["render",t]]);export{u as __pageData,b as default};
